touch prueba.txt #Creates the file prueba.txt if it does not exist, or updates its modification timestamp if it already exists.
chmod 600 prueba.txt #Changes the permissions so that only the owner can read and write the file.
 ls -l prueba.txt #Displays the file details, including its current permissions.
 chmod 755 prueba.txt #Changes the permissions so that the owner can read, write, and execute the file, while others can only read and execute it.
 ls -l prueba.txt #Displays the file details again to verify the permission changes.